import{c as r,Z as a,Q as n,j as i,o as l,m as o}from"./chunks/framework.qjzPVSkb.js";const p=JSON.parse('{"title":"训练 / 推理","description":"训练是模型学习阶段，推理是模型使用阶段——二者的区别与关系","frontmatter":{"title":"训练 / 推理","description":"训练是模型学习阶段，推理是模型使用阶段——二者的区别与关系","difficulty":"beginner"},"headers":[],"relativePath":"terms/training-inference.md","filePath":"terms/training-inference.md"}'),d={name:"terms/training-inference.md"};function s(h,t,c,g,u,f){const e=a("DifficultyBadge");return n(),i("div",null,[l(e,{level:"beginner"}),t[0]||(t[0]=o('<h1 id="训练-推理" tabindex="-1">训练 / 推理 <a class="header-anchor" href="#训练-推理" aria-label="Permalink to &quot;训练 / 推理&quot;">​</a></h1><p>很多人在谈论 AI 时把&quot;训练&quot;和&quot;推理&quot;混为一谈，但它们像<strong>上学和工作</strong>——是完全不同的两个阶段。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p><strong>训练（Training）</strong> 是让模型从海量数据中学习模式和规律的过程，需要大量 GPU 和时间，成本极高；<strong>推理（Inference）</strong> 是使用训练好的模型对新输入做出预测或生成输出，速度快、成本相对低。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p><strong>训练 = 上学读书</strong></p><ul><li>你花 16 年上学，读了成千上万本书，做了无数道题</li><li>这期间需要教室（GPU 集群）、老师（优化算法）、课本（训练数据）</li><li>成本非常高，但一生只做一次（或几次）</li></ul><p><strong>推理 = 毕业工作</strong></p><ul><li>学成后，有人问问题，你用学到的知识回答</li><li>不需要大量计算资源，一台电脑（一张 GPU）就可能够用</li><li>每次回答成本低，但一辈子都在做这件事</li></ul><p>GPT-4 的训练花了约 <strong>7800 万美元</strong>（算力成本），但我们每次用 ChatGPT 问问题只花几分钱。这就是训练和推理的区别。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>训练</th><th>推理</th></tr></thead><tbody><tr><td>目的</td><td>学习数据中的模式</td><td>对新输入做出预测</td></tr><tr><td>参数状态</td><td>不断更新（梯度下降）</td><td>固定不变（只读）</td></tr><tr><td>硬件需求</td><td>数千张 GPU，数月</td><td>1~8 张 GPU，毫秒级</td></tr><tr><td>数据流</td><td>前向计算 + 反向传播</td><td>仅前向计算</td></tr><tr><td>成本</td><td>千万~亿美元级</td><td>每次几厘到几分钱</td></tr><tr><td>执行者</td><td>大公司/研究机构</td><td>用户（通过 API 或本地）</td></tr></tbody></table><p>训练中还有一个重要概念：<strong>梯度下降</strong>。简单理解，就是每次看一批数据→计算预测和正确答案的差距→微调参数让差距变小——这个过程循环数百万次。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/parameters.html">参数</a> —— 训练更新参数，推理使用参数</li><li><a href="/ai-knowledge/terms/fine-tuning.html">微调 (Fine-tuning)</a> —— 在已训练模型上的二次训练</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://cloud.google.com/discover/what-is-inference-in-machine-learning" target="_blank" rel="noreferrer">Google: ML Training vs Inference</a></li><li><a href="https://blogs.nvidia.com/blog/whats-the-difference-between-single--double--multi-and-mixed-precision-computing/" target="_blank" rel="noreferrer">NVIDIA: Training vs Inference</a></li></ul>',17))])}const b=r(d,[["render",s]]);export{p as __pageData,b as default};
